async function describeLlmAuth(
  provider: RuntimeLlmProvider,
  creds: StoredCredentials,
): Promise<string> {
  if (provider === "openai") {
    if (creds.openai) {
      return `OpenAI OAuth credentials present (expires ${new Date(creds.openai.expires).toISOString()})`;
